          "/* Scoped agent-UI chrome for the homepage agent-review demo. Everything lives\n   under `.aui` so it never leaks into the rest of the docs app. Colours use\n   light-dark(); the `.aui[data-theme-type]` rules pin color-scheme to the\n   demo's own toggle. The UI sits in normal page flow as a fixed-height card. */\n.aui {\n  --ide-surface: light-dark(#ffffff, #070707);\n  --ide-panel: light-dark(#f8f8f8, #0f0f10);\n  --ide-border: light-dark(rgb(0 0 0 / 0.08), rgb(255 255 255 / 0.07));\n  --ide-fg: light-dark(#18181b, #e4e4e7);\n  --ide-fg-muted: light-dark(#71717a, #a1a1aa);\n  --ide-tab-active: light-dark(#ffffff, #1c1c1f);\n  --ide-tab-hover: light-dark(rgb(0 0 0 / 0.04), rgb(255 255 255 / 0.05));\n  --ide-accent: light-dark(#2563eb, #3b82f6);\n\n  display: grid;\n  grid-template-rows: minmax(0, 1fr);\n  height: 560px;\n  max-height: 72vh;\n  border: 1px solid var(--ide-border);\n  border-radius: 12px;\n  overflow: hidden;\n  box-shadow: 0 1px 2px rgb(0 0 0 / 0.05);\n  background-color: var(--ide-surface);\n  color: var(--ide-fg);\n  font-family: var(--font-geist-sans), system-ui, sans-serif;\n  font-size: 13px;\n}\n\n.aui[data-theme-type='light'] {\n  color-scheme: light;\n}\n\n.aui[data-theme-type='dark'] {\n  color-scheme: dark;\n}\n\n/* Give the demo more room on desktop. */\n@media (width >= 1024px) {\n  .aui {\n    height: 760px;\n    max-height: 75vh;\n  }\n}\n\n.aui button {\n  font-family: inherit;\n  cursor: pointer;\n}\n\n.aui code {\n  font-family: var(--font-berkeley-mono), monospace;\n  font-size: 0.9em;\n  padding: 1px 4px;\n  border-radius: 4px;\n  background-color: var(--ide-tab-hover);\n}\n\n.aui-body {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) 380px;\n  min-height: 0;\n}\n\n/* --- Center column ------------------------------------------------------- */\n\n.aui-center {\n  display: flex;\n  flex-direction: column;\n  min-width: 0;\n  min-height: 0;\n}\n\n.aui-center-header {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 12px;\n  height: 44px;\n  padding-inline: 12px;\n  border-bottom: 1px solid var(--ide-border);\n}\n\n.aui-breadcrumb {\n  display: flex;\n  align-items: center;\n  min-width: 0;\n  overflow: hidden;\n  font-size: 14px;\n  color: var(--ide-fg-muted);\n}\n\n.aui-crumb:not(:last-child)::after {\n  content: '/';\n  margin-inline: 2px;\n  opacity: 0.5;\n}\n\n.aui-crumb[data-leaf='true'] {\n  color: var(--ide-fg);\n  font-weight: 500;\n}\n\n.aui-surface-wrap {\n  position: relative;\n  flex: 1;\n  min-height: 0;\n  overflow: auto;\n  overscroll-behavior: contain;\n}\n\n.aui-surface {\n  display: block;\n}\n\n.aui-empty {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  height: 100%;\n  color: var(--ide-fg-muted);\n}\n\n.aui-selection-action {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n  padding: 8px 0;\n}\n\n.aui-selection-action button {\n  padding: 4px 10px;\n  border-radius: 6px;\n  border: 1px solid color-mix(in srgb, currentColor 35%, transparent);\n  background-color: color-mix(in srgb, currentColor 8%, transparent);\n  color: inherit;\n  font-size: 12px;\n}\n\n.aui-composer {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n  margin: 12px;\n  padding: 10px 10px 8px;\n  border: 1px solid var(--ide-border);\n  border-radius: 12px;\n  background-color: var(--ide-panel);\n}\n\n.aui-composer:focus-within {\n  border-color: var(--ide-accent);\n}\n\n.aui-composer-input {\n  width: 100%;\n  min-height: 40px;\n  padding: 2px 4px;\n  border: none;\n  background: none;\n  color: var(--ide-fg);\n  font-size: 13px;\n  font-family: inherit;\n  line-height: 1.5;\n  resize: none;\n}\n\n.aui-composer-input:focus {\n  outline: none;\n}\n\n.aui-composer-input::placeholder {\n  color: var(--ide-fg-muted);\n}\n\n.aui-composer-toolbar {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n}\n\n.aui-composer-select,\n.aui-composer-send {\n  display: inline-flex;\n  align-items: center;\n  border: 0;\n  border-radius: 9px;\n  background: none;\n  color: var(--ide-fg-muted);\n\n  &[disabled] {\n    cursor: default;\n  }\n}\n\n.aui-composer-select {\n  gap: 5px;\n  height: 28px;\n  padding-inline: 8px;\n  background-color: var(--ide-tab-hover);\n  font-size: 12px;\n}\n\n.aui-composer-send {\n  justify-content: center;\n  width: 28px;\n  height: 28px;\n  background-color: var(--ide-accent);\n  color: #ffffff;\n\n  &[disabled] {\n    opacity: 0.6;\n  }\n}\n\n/* --- Right changes panel ------------------------------------------------- */\n\n.aui-changes {\n  display: flex;\n  flex-direction: column;\n  min-height: 0;\n  border-left: 1px solid var(--ide-border);\n  background-color: var(--ide-panel);\n}\n\n.aui-changes-tabs {\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  height: 44px;\n  padding-inline: 10px;\n  border-bottom: 1px solid var(--ide-border);\n}\n\n.aui-changes-tabs button {\n  padding: 4px 10px;\n  border: none;\n  border-radius: 6px;\n  background-color: transparent;\n  color: var(--ide-fg-muted);\n  font-size: 12px;\n}\n\n.aui-changes-tabs button[aria-selected='true'] {\n  background-color: var(--ide-tab-active);\n  color: var(--ide-fg);\n}\n\n.aui-changes-tabs button[disabled] {\n  cursor: default;\n  opacity: 0.6;\n}\n\n.aui-tree {\n  flex: 1;\n  min-height: 0;\n  overflow: auto;\n  padding-top: 6px;\n}\n\n/* --- Mobile -------------------------------------------------------------- */\n\n/* On narrow screens there isn't room for the changes sidebar, so collapse to a\n   single full-width column showing just the active file. Placed last so it wins\n   over the base `.aui-body`/`.aui-changes` rules above (media queries don't add\n   specificity). */\n@media (width < 640px) {\n  .aui-body {\n    grid-template-columns: minmax(0, 1fr);\n  }\n\n  .aui-changes {\n    display: none;\n  }\n}\n",
